What does this program print?

```cpp
#include <iostream>
#include <memory>

void take(std::unique_ptr<int> p) {
    std::cout << *p << "\n";
}

int main() {
    auto p = std::make_unique<int>(77);
    take(std::move(p));
    std::cout << (p ? "not null" : "null") << "\n";
    return 0;
}
